# Tilted Card

Framer Motion 3D parallax card that tilts based on cursor position with spring physics, optional overlay content with translateZ depth, and a cursor-following tooltip.

## Use when
- Showcasing a product image or album art with premium 3D tilt interaction.
- Adding a cursor-reactive depth effect to a card or feature highlight.
- Drawing attention to a CTA or value proposition with tactile feedback.

## Stack
- Framework: react
- Libraries: framer-motion

## Install
```bash
npm install framer-motion
```

## Component — tilted-card.tsx
```tsx
import type { SpringOptions } from 'framer-motion';
import { useRef, useState } from 'react';
import { motion, useMotionValue, useSpring } from 'framer-motion';

export interface TiltedCardProps {
  imageSrc: string;
  altText?: string;
  captionText?: string;
  containerHeight?: React.CSSProperties['height'];
  containerWidth?: React.CSSProperties['width'];
  imageHeight?: React.CSSProperties['height'];
  imageWidth?: React.CSSProperties['width'];
  scaleOnHover?: number;
  rotateAmplitude?: number;
  showMobileWarning?: boolean;
  showTooltip?: boolean;
  overlayContent?: React.ReactNode;
  displayOverlayContent?: boolean;
  className?: string;
}

const springValues: SpringOptions = { damping: 30, stiffness: 100, mass: 2 };

export const TiltedCard = ({
  imageSrc,
  altText = 'Tilted card image',
  captionText = '',
  containerHeight = '300px',
  containerWidth = '100%',
  imageHeight = '300px',
  imageWidth = '300px',
  scaleOnHover = 1.1,
  rotateAmplitude = 14,
  showMobileWarning = true,
  showTooltip = true,
  overlayContent = null,
  displayOverlayContent = false,
  className = ''
}: TiltedCardProps) => {
  const ref = useRef<HTMLElement>(null);
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const rotateX = useSpring(useMotionValue(0), springValues);
  const rotateY = useSpring(useMotionValue(0), springValues);
  const scale = useSpring(1, springValues);
  const opacity = useSpring(0);
  const rotateFigcaption = useSpring(0, { stiffness: 350, damping: 30, mass: 1 });
  const [lastY, setLastY] = useState(0);

  function handleMouse(e: React.MouseEvent<HTMLElement>) {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const offsetX = e.clientX - rect.left - rect.width / 2;
    const offsetY = e.clientY - rect.top - rect.height / 2;
    rotateX.set((offsetY / (rect.height / 2)) * -rotateAmplitude);
    rotateY.set((offsetX / (rect.width / 2)) * rotateAmplitude);
    x.set(e.clientX - rect.left);
    y.set(e.clientY - rect.top);
    const velocityY = offsetY - lastY;
    rotateFigcaption.set(-velocityY * 0.6);
    setLastY(offsetY);
  }

  function handleMouseEnter() { scale.set(scaleOnHover); opacity.set(1); }
  function handleMouseLeave() { opacity.set(0); scale.set(1); rotateX.set(0); rotateY.set(0); rotateFigcaption.set(0); }

  return (
    <figure ref={ref} className={`relative w-full h-full [perspective:800px] flex flex-col items-center justify-center ${className}`} style={{ height: containerHeight, width: containerWidth }} onMouseMove={handleMouse} onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseLeave}>
      {showMobileWarning && (<div className="absolute top-4 text-center text-sm block sm:hidden text-muted-foreground">This effect is optimized for desktop.</div>)}
      <motion.div className="relative [transform-style:preserve-3d]" style={{ width: imageWidth, height: imageHeight, rotateX, rotateY, scale }}>
        <motion.img src={imageSrc} alt={altText} className="absolute top-0 left-0 object-cover rounded-[15px] border border-border/50 shadow-2xl will-change-transform [transform:translateZ(0)]" style={{ width: imageWidth, height: imageHeight }} />
        {displayOverlayContent && overlayContent && (<motion.div className="absolute top-0 left-0 z-[2] w-full h-full flex items-center justify-center will-change-transform [transform:translateZ(30px)] pointer-events-none">{overlayContent}</motion.div>)}
      </motion.div>
      {showTooltip && (<motion.figcaption className="pointer-events-none absolute left-0 top-0 rounded-[4px] bg-background border border-border px-[10px] py-[4px] text-[10px] text-foreground shadow-lg opacity-0 z-[3] hidden sm:block whitespace-nowrap" style={{ x, y, opacity, rotate: rotateFigcaption }}>{captionText}</motion.figcaption>)}
    </figure>
  );
};

export default TiltedCard;
```

## Demo
```tsx
import { TiltedCard } from './Component';

export default function App() {
  return (
    <div className="min-h-screen bg-[#F9F9F9] flex flex-col items-center justify-center p-20 font-sans">
      <div className="flex flex-col items-center gap-12">
        <h1 className="text-2xl font-medium text-[#1A1A1B] tracking-tight">Tilted Card Animation</h1>
        <div className="p-20 bg-white rounded-[40px] shadow-[0_20px_40px_rgba(0,0,0,0.05)] border border-transparent">
          <TiltedCard imageSrc="https://i.scdn.co/image/ab67616d0000b273d9985092cd88bffd97653b58" altText="Album Cover" captionText="Kendrick Lamar - GNX" containerHeight="400px" containerWidth="400px" imageHeight="300px" imageWidth="300px" rotateAmplitude={12} scaleOnHover={1.2} showMobileWarning={false} showTooltip={true} displayOverlayContent={true} overlayContent={<div className="bg-black/40 backdrop-blur-md px-4 py-2 rounded-full border border-white/20"><p className="text-white text-sm font-medium">GNX</p></div>} />
        </div>
      </div>
    </div>
  );
}
```
